 39	/*!
 40	    \brief      deinitialize DAC
 41	    \param[in]  none
 42	    \param[out] none
 43	    \retval     none
 44	*/
 45	void dac_deinit(void)
 46	{
 47	    rcu_periph_reset_enable(RCU_DACRST);
 48	    rcu_periph_reset_disable(RCU_DACRST);
 49	}
