 51	/*!
 52	    \brief      enable DAC
 53	    \param[in]  dac_periph
 54	      \arg        DACx(x =0,1)
 55	    \param[out] none
 56	    \retval     none
 57	*/
 58	void dac_enable(uint32_t dac_periph)
 59	{
 60	    if (DAC0 == dac_periph) {
 61	        DAC_CTL |= DAC_CTL_DEN0;
 62	    } else {
 63	        DAC_CTL |= DAC_CTL_DEN1;
 64	    }
 65	}
