 71	    \param[out] none
 72	    \retval     none
 73	*/
 74	void dac_disable(uint32_t dac_periph)
 75	{
 76	    if (DAC0 == dac_periph) {
 77	        DAC_CTL &= ~DAC_CTL_DEN0;
 78	    } else {
 79	        DAC_CTL &= ~DAC_CTL_DEN1;
 80	    }
 81	}
